class Chemical{
  constructor(chem_id, name, chem_relationship, dtxcid, parent_name, dtxsid, cas1, cas2){
    this.chem_id = chem_id;
    this.name = name;
    this.chem_relationship = chem_relationship;
    this.dtxcid = dtxcid;
    this.parent_name = parent_name;
    this.dtxsid = dtxsid;
    this.parent_dtxcid = 0;
    this.cas1 = cas1;
    this.cas2 = cas2;
    this.ref_list = new Array();
    this.ref_list = new Array();
    this.percent_sim = -1;
  }
}

class Model{
  constructor(chem_id, chem_plus, population_id, route_id, refId, equation_id, software_id, notes){
    this.chem_id = chem_id;
    this.chem_plus = chem_plus; // This is a string (or blank)
    this.population_id = population_id;
    this.route_id = route_id;
    this.refId = refId;
    this.compartmentsList = new Array();
    this.equation_id = equation_id;
    this.software_id = software_id;
    this.notes = notes;
  }
}

class Population{
  constructor(species_id, gender_id, stage_id){
    this.species_id   = species_id;
    this.gender_id    = gender_id;
    this.stage_id = stage_id;
  }
}

class Reference{
  constructor(author,year,journal,vol,pages,pubmed_id,doi){
    this.author    = author    ;
    this.year      = year      ;
    this.journal   = journal   ;
    this.vol       = vol       ;
    this.pages     = pages     ;
    this.pubmed_id = pubmed_id ;
    this.doi       = doi       ;
  }
}

